const platform = $input.first().json.platform;
const type     = $input.first().json.type || 'auto';
const topic    = $input.first().json.topic || '';

// Load prompt templates (in production, read from files or store in n8n variables)
const prompts = {
  instagram: `You are Symponia's Instagram specialist with deep platform expertise. Generate viral Instagram content for Symponia philosophical AI app. Return ONLY valid JSON with these fields: platform, contentType, hook, caption, hashtags, script (if reel), slides (array if carousel), visualPrompt, trendReference, viralScore (1-10), notes.`,
  tiktok:    `You are Symponia's TikTok specialist with deep platform expertise. Generate viral TikTok content for Symponia philosophical AI app. Return ONLY valid JSON with these fields: platform, contentType, hook, caption, hashtags, script (timestamped), soundSuggestion, textOverlays (array), visualPrompt, trendReference, seriesPotential (bool), viralScore (1-10), notes.`,
  linkedin:  `You are Symponia's LinkedIn specialist with deep platform expertise. Generate professional LinkedIn content for Symponia philosophical AI app. Return ONLY valid JSON with these fields: platform, contentType, hook, post (full post text), caption, hashtags, firstComment (for app link), slides (array if document), visualPrompt, postingNote, trendReference, viralScore (1-10), notes.`
};

const userMessages = {
  auto:      `Generate the highest-impact ${platform} content for Symponia right now. Choose the best format for current trends.`,
  reel:      `Generate a Reel/video concept for Symponia on ${platform}. Hook in first 3 seconds. Full script.`,
  carousel:  `Generate a carousel post for Symponia on ${platform}. 7-10 slides. Hook on slide 1. CTA on last slide.`,
  'short-post': `Generate a short ${platform} post for Symponia. Maximum impact, minimum words.`,
  'document-carousel': `Generate a LinkedIn document carousel for Symponia. 10-12 slides with position labels.`,
  series:    `Generate Part 1 of a TikTok series for Symponia. End with a cliffhanger.`,
};

const systemPrompt = prompts[platform];
const baseMessage  = userMessages[type] || userMessages.auto;
const userMessage  = topic
  ? `${baseMessage}\n\nFocus on this topic: ${topic}`
  : baseMessage;

return [{ json: { systemPrompt, userMessage, platform } }];

const raw = $input.first().json.content[0].text;
const platform = $node['Build Prompt'].json.platform;

// Extract JSON from Claude's response
const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/) || raw.match(/(\{[\s\S]*\})/);
const jsonStr = match ? match[1].trim() : raw.trim();

let content;
try {
  content = JSON.parse(jsonStr);
} catch(e) {
  throw new Error('Failed to parse Claude output: ' + e.message);
}

return [{ json: { ...content, platform, rawOutput: raw } }];

